/**
 * Generation types for elements:
 * - ai_generated: AI generates content, ready to use
 * - manual_preferred: User provides (logo, hero_image), has defaults
 * - ai_generated_needs_review: AI generates placeholder, flagged "Verify this"
 * - system: Auto-generated by code (IDs, timestamps)
 * - hybrid: Mix of AI and manual (legacy, avoid using)
 */
export type GenerationType = 'ai_generated' | 'manual_preferred' | 'ai_generated_needs_review' | 'system' | 'hybrid';

export type RequirementType = 'required' | 'optional';

// =============================================================================
// NEW SCHEMA FORMAT (V2) - Clean arrays, no pipe strings
// =============================================================================

/** Element definition in new schema format */
export interface ElementDef {
  type: 'string' | 'boolean' | 'number';
  requirement?: RequirementType;  // Only applies to ai_generated
  fillMode: GenerationType;
  default?: any;  // Placeholder for manual_preferred
}

/** Collection field definition */
export interface CollectionFieldDef {
  type: 'string' | 'boolean' | 'number' | 'string[]' | 'array';
  fillMode: GenerationType;
  default?: any;
  constraints?: { min: number; max: number };
  fields?: Record<string, CollectionFieldDef>;  // For nested arrays
}

/** Collection (array of items) definition */
export interface CollectionDef {
  requirement: RequirementType;
  fillMode: GenerationType;
  constraints: { min: number; max: number };
  fields: Record<string, CollectionFieldDef>;
}

/** New UIBlock schema format (V2) */
export interface UIBlockSchemaV2 {
  sectionType: string;
  elements: Record<string, ElementDef>;
  collections?: Record<string, CollectionDef>;
}

// =============================================================================
// LEGACY SCHEMA FORMAT (V1) - For backward compatibility during migration
// =============================================================================

export interface LayoutElement {
  element: string;
  mandatory: boolean;
  generation?: GenerationType;
  isCard?: boolean; // Indicates if this element is part of a card structure
  description?: string; // Optional description or guidance for the element
  charLimit?: number; // Maximum character length for this element
}

export interface CardStructure {
  type: 'cards' | 'pairs' | 'items' | 'blocks' | 'steps' | 'triplets' | 'quadruplets' | 'sextuplets' | 'tabbed_pairs' | 'rows' | 'usage_based' | 'column_pairs';
  elements: string[];  // All card elements are mandatory by default
  generation: GenerationType;
}

export interface CardRequirements {
  type: string;
  min: number;
  max: number;
  optimal: [number, number];
  description: string;
  respectUserContent?: boolean; // Prioritize user-provided features
}

export interface UnifiedLayoutElement {
  sectionElements: LayoutElement[];
  cardStructure?: CardStructure;
  cardRequirements: CardRequirements | null;
}

// =============================================================================
// COMBINED SCHEMA TYPE - Supports both V1 and V2 formats
// =============================================================================

export interface LayoutSchema {
  [layoutName: string]: LayoutElement[] | UnifiedLayoutElement | UIBlockSchemaV2;
}

// =============================================================================
// HELPER FUNCTIONS - Support V1 (legacy) and V2 (new) schema formats
// =============================================================================

type AnySchema = LayoutElement[] | UnifiedLayoutElement | UIBlockSchemaV2;

/** Check if schema is V2 format */
export function isV2Schema(schema: AnySchema): schema is UIBlockSchemaV2 {
  return typeof schema === 'object' && !Array.isArray(schema) && 'sectionType' in schema && 'elements' in schema;
}

/** Check if schema is V1 unified format */
export function isUnifiedSchema(schema: AnySchema): schema is UnifiedLayoutElement {
  return typeof schema === 'object' && !Array.isArray(schema) && 'sectionElements' in schema;
}

/** Convert V2 elements to V1 LayoutElement[] for backward compatibility */
function v2ElementsToV1(schema: UIBlockSchemaV2): LayoutElement[] {
  const elements: LayoutElement[] = [];

  // Convert section elements
  for (const [key, def] of Object.entries(schema.elements)) {
    elements.push({
      element: key,
      mandatory: def.requirement === 'required',
      generation: def.fillMode
    });
  }

  // Convert collection fields (excluding 'id' which is system-generated)
  if (schema.collections) {
    for (const [collectionName, collection] of Object.entries(schema.collections)) {
      for (const [fieldKey, fieldDef] of Object.entries(collection.fields)) {
        if (fieldDef.fillMode !== 'system') {
          elements.push({
            element: `${collectionName}.${fieldKey}`,
            mandatory: collection.requirement === 'required',
            generation: fieldDef.fillMode,
            isCard: true
          });
        }
      }
    }
  }

  return elements;
}

/** Get all elements from any schema format (returns V1 format for compatibility) */
export function getAllElements(schema: AnySchema): LayoutElement[] {
  if (isV2Schema(schema)) {
    return v2ElementsToV1(schema);
  }
  if (isUnifiedSchema(schema)) {
    const cardElements = schema.cardStructure ? schema.cardStructure.elements.map(elementName => ({
      element: elementName,
      mandatory: true,
      generation: schema.cardStructure!.generation
    })) : [];
    return [...schema.sectionElements, ...cardElements];
  }
  return schema;
}

/** Get layout elements safely for any schema format */
export function getLayoutElements(layoutName: string): LayoutElement[] {
  const schema = layoutElementSchema[layoutName];
  if (!schema) {
    return [];
  }
  return getAllElements(schema);
}

/** Get section elements (non-card elements) */
export function getSectionElements(schema: AnySchema): LayoutElement[] {
  if (isV2Schema(schema)) {
    return Object.entries(schema.elements).map(([key, def]) => ({
      element: key,
      mandatory: def.requirement === 'required',
      generation: def.fillMode
    }));
  }
  if (isUnifiedSchema(schema)) {
    return schema.sectionElements;
  }
  return schema;
}

/** Get card/collection elements */
export function getCardElements(schema: AnySchema): LayoutElement[] {
  if (isV2Schema(schema) && schema.collections) {
    const elements: LayoutElement[] = [];
    for (const [collectionName, collection] of Object.entries(schema.collections)) {
      for (const [fieldKey, fieldDef] of Object.entries(collection.fields)) {
        if (fieldDef.fillMode !== 'system') {
          elements.push({
            element: `${collectionName}.${fieldKey}`,
            mandatory: collection.requirement === 'required',
            generation: fieldDef.fillMode,
            isCard: true
          });
        }
      }
    }
    return elements;
  }
  if (isUnifiedSchema(schema) && schema.cardStructure) {
    return schema.cardStructure.elements.map(elementName => ({
      element: elementName,
      mandatory: true,
      generation: schema.cardStructure!.generation
    }));
  }
  return [];
}

/** Get card requirements from any schema format */
export function getCardRequirements(schema: AnySchema): CardRequirements | null {
  if (isV2Schema(schema) && schema.collections) {
    // Return requirements for first collection (most UIBlocks have one)
    const firstCollection = Object.entries(schema.collections)[0];
    if (firstCollection) {
      const [name, def] = firstCollection;
      return {
        type: name,
        min: def.constraints.min,
        max: def.constraints.max,
        optimal: [def.constraints.min, def.constraints.max],
        description: `${name} items`
      };
    }
  }
  if (isUnifiedSchema(schema)) {
    return schema.cardRequirements || null;
  }
  return null;
}

/**
 * Apply schema defaults for V2 schemas.
 * Injects manual_preferred defaults for elements not present in AI output.
 */
export function applySchemaDefaults(
  uiblockName: string,
  aiElements: Record<string, any>
): Record<string, any> {
  const schema = layoutElementSchema[uiblockName];
  if (!schema || !isV2Schema(schema)) {
    // Still filter nulls for non-V2 schemas
    return Object.fromEntries(
      Object.entries(aiElements).filter(([_, v]) => v !== null)
    );
  }

  // Filter out null values from AI response (Claude returns explicit nulls for optional elements)
  const result = Object.fromEntries(
    Object.entries(aiElements).filter(([_, v]) => v !== null)
  );

  // Apply element defaults - ONLY for required manual_preferred
  for (const [key, def] of Object.entries(schema.elements)) {
    if (def.fillMode === 'manual_preferred' &&
        def.requirement === 'required' &&
        def.default !== undefined) {
      if (result[key] === undefined || result[key] === null) {
        result[key] = def.default;
      }
    }
  }

  // Apply collection defaults - ONLY for required manual_preferred
  if (schema.collections) {
    for (const [name, collection] of Object.entries(schema.collections)) {
      if (collection.fillMode === 'manual_preferred' &&
          collection.requirement === 'required') {
        if (result[name] === undefined || result[name] === null) {
          result[name] = [];
        }
      }
    }
  }

  return result;
}

/**
 * Apply schema defaults to all sections in copy response.
 */
export function applyAllSchemaDefaults(
  sections: Record<string, { elements: Record<string, any> }>,
  uiblocks: Record<string, string>
): Record<string, { elements: Record<string, any> }> {
  const result: Record<string, { elements: Record<string, any> }> = {};

  for (const [sectionName, sectionCopy] of Object.entries(sections)) {
    const uiblockName = uiblocks[sectionName];
    result[sectionName] = {
      elements: uiblockName
        ? applySchemaDefaults(uiblockName, sectionCopy.elements || {})
        : (sectionCopy.elements || {})
    };
  }

  return result;
}

